import 'package:flutter/material.dart';import 'package:flutter_app/pages/ProfileDetailPage.dart';// класс пункта меню страницы профиля,// который будет хранить имя и описание, а также idclass ProfScrElem {  final int id;  final String name;  final String desc;  ProfScrElem(this.id, this.name, this.desc);}// создаем список пунктов меню страницы профиля// final указывает на то, что мы больше// никогда не сможем присвоить имени ProfScrElems// другой список пунктов меню страницы профиляfinal List<ProfScrElem> ProfScrElems = [  ProfScrElem(      0,      "Васёк",      "Просмотр профиля в доработке"  ),  ProfScrElem(      1,      "Мои мероприятия",      "Просмотр мероприятий в доработке"  ),  ProfScrElem(      2,      "Настройки",      "Настройки в доработке"  ),  ProfScrElem(      3,      "Выход",      "Вы действительно хотите выйти?"  ),];// ProfileListPage не будет иметь состояния,// т.к. этот пример создан только для демонстрации// навигации в действииclass ProfileListPage extends StatelessWidget {  // build как мы уже отметили, строит  // иерархию наших любимых виджетов  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(title: Text("Профиль")),      // зададим небольшие отступы для списка      body: Padding(        // объект EdgeInsets хранит четыре важные double переменные:        // left, top, right, bottom - отступ слева, сверху, справа и снизу        // EdgeInsets.all(10) - задает одинаковый отступ со всех сторон        // EdgeInsets.only(left: 10, right: 15) - задает отступ для        // определенной стороны или сторон        // EdgeInsets.symmetric - позволяет указать одинаковые        // отступы по горизонтали (left и right) и по вертикали (top и bottom)          padding: EdgeInsets.symmetric(vertical: 0, horizontal: 0),          // создаем наш список          child: ListView(            // map принимает другую функцию, которая            // будет выполняться над каждым элементом            // списка и возвращать новый элемент (виджет Material).            // Результатом map является новый список            // с новыми элементами, в данном случае            // это Material виджеты            children: ProfScrElems.map<Widget>((elem) {              // Material используется для того,              // чтобы указать цвет элементу списка              // и применить ripple эффект при нажатии на него              return Material(                color: Colors.black12,                // InkWell позволяет отслеживать                // различные события, например: нажатие                child: InkWell(                  // splashColor - цвет ripple эффекта                  splashColor: Colors.black12,                  // нажатие на элемент списка                  onTap: () {                    // Здесь мы используем сокращенную форму:                    // Navigator.of(context).push(route)                    // ProfileDetailPage принимает elem id,                    // который мы и передали                    Navigator.push(context, MaterialPageRoute(                        builder: (context) => ProfileDetailPage(elem.id)                    ));                  },                  // далее указываем в качестве                  // элемента Container с вложенным Text                  // Container позволяет указать внутренние (padding)                  // и внешние отступы (margin),                  // а также тень, закругление углов,                  // цвет и размеры вложенного виджета                  child: Container(                      padding: EdgeInsets.all(20),                      child: Center(child: Text(                          elem.name,                          style: Theme.of(context).textTheme.bodyLarge                      ))                  ),                ),              );              // map возвращает Iterable объект, который необходимо              // преобразовать в список с помощью toList() функции            }).toList(),          )      ),    );  }}